{
  "lessons": [
    {
      "concepts": [
        "Archaeological Evidence",
        "Oral Tradition",
        "Colonial Chroniclers",
        "Dating Methods"
      ],
      "description": "Work with the main kinds of evidence used to recover Indigenous histories before 1500. Notice what each source can reveal, and what can get lost or distorted in the record.",
      "title": "Rebuilding histories from fragmentary evidence"
    },
    {
      "concepts": [
        "Sambaquis",
        "Amazonian Dark Earth",
        "Rock Art Sites",
        "Mound Villages"
      ],
      "description": "Meet the material traces that prove long Indigenous presence and landscape shaping across Brazil. These sites make precolonial life visible even where written records are absent.",
      "title": "Reading the land for signs of older worlds"
    },
    {
      "concepts": [
        "Population Diversity",
        "Regional Ecologies",
        "Mobility Patterns"
      ],
      "description": "Start from the fact that precolonial Brazil was never one people or one way of life. Place communities in forests, coasts, rivers, and grasslands to see how place shaped daily choices.",
      "title": "Seeing many Brazils before 1500"
    },
    {
      "concepts": [
        "Tupi Languages",
        "Macro-Jê Languages",
        "Arawak Languages",
        "Karib Languages",
        "Language Families"
      ],
      "description": "Use language to map broad relationships among peoples without collapsing their differences. These language families help trace contact, movement, and cultural exchange across large regions.",
      "title": "Tracing peoples through language families"
    },
    {
      "concepts": [
        "Coastal Tupi Expansion",
        "Arawak River Networks",
        "Jê Interior Occupation"
      ],
      "description": "Follow major patterns of movement and settlement that shaped who lived where before colonization. These paths help explain later encounters recorded on the coast and inland.",
      "title": "Following major movements across the territory"
    },
    {
      "concepts": [
        "Manioc Cultivation",
        "Maize Cultivation",
        "Slash-and-Burn Farming",
        "Fishing Techniques",
        "Hunting Practices"
      ],
      "description": "Look at how communities secured food through farming, rivers, forests, and seasonal knowledge. Subsistence was skilled environmental management, not mere survival.",
      "title": "Growing food and living with local ecologies"
    },
    {
      "concepts": [
        "Food Storage",
        "Ceramic Vessels",
        "Basketry",
        "Lithic Tools",
        "Wooden Tools"
      ],
      "description": "Focus on the everyday technologies that made farming, cooking, transport, and craft production possible. Small tools and containers reveal a lot about settled life and specialized knowledge.",
      "title": "Using tools that made daily life work"
    },
    {
      "concepts": [
        "Village Layout",
        "Malocas",
        "Household Labor",
        "Gendered Tasks"
      ],
      "description": "Step inside village life to see how people organized homes, work, and shared space. Social structure becomes easier to grasp when daily routines and built spaces come into view.",
      "title": "Organizing life in villages and households"
    },
    {
      "concepts": [
        "River Exchange",
        "Coastal Exchange",
        "Ceramic Circulation",
        "Stone Circulation"
      ],
      "description": "Track how goods moved across long distances before Europeans arrived. Trade networks linked communities through rivers, trails, and shorelines rather than isolated local worlds.",
      "title": "Following trade across rivers, trails, and coasts"
    },
    {
      "concepts": [
        "Feasting",
        "Gift Exchange",
        "Marriage Alliances",
        "Intergroup Diplomacy"
      ],
      "description": "See exchange as more than economics. Goods, visits, marriages, and rituals also built trust, status, and political ties between communities.",
      "title": "Building relationships through exchange"
    },
    {
      "concepts": [
        "War Captivity",
        "Revenge Warfare",
        "Raiding Practices",
        "War Leadership"
      ],
      "description": "Examine conflict on its own terms instead of through colonial stereotypes. Warfare often followed rules tied to honor, memory, alliance, and the taking of captives.",
      "title": "Understanding warfare beyond colonial stereotypes"
    },
    {
      "concepts": [
        "Cannibalism Rituals",
        "Captive Incorporation",
        "Body Ornamentation",
        "War Prestige"
      ],
      "description": "Look closely at practices that Europeans described with fear and fascination. Place them back in Indigenous systems of meaning, status, and social reproduction.",
      "title": "Placing ritual warfare in Indigenous meanings"
    },
    {
      "concepts": [
        "Shamans",
        "Healing Rituals",
        "Spirit Beings",
        "Dream Knowledge",
        "Sacred Landscapes"
      ],
      "description": "Enter belief systems where health, power, land, and unseen beings were deeply connected. Spiritual authority shaped medicine, leadership, and relations with the environment.",
      "title": "Meeting the spiritual authorities of community life"
    },
    {
      "concepts": [
        "Ancestor Memory",
        "Funerary Practices",
        "Creation Narratives",
        "Ritual Speech"
      ],
      "description": "Follow the stories and ceremonies that linked people to origins, ancestors, and collective memory. These practices carried history as much as belief.",
      "title": "Keeping memory alive through ritual and story"
    },
    {
      "concepts": [
        "Forest Management",
        "Controlled Burning",
        "Agroforestry",
        "Anthropogenic Landscapes"
      ],
      "description": "Challenge the idea of untouched wilderness by looking at how Indigenous peoples actively shaped environments. Farming, fire, and planting created durable human-made landscapes.",
      "title": "Recognizing landscapes shaped by human care"
    },
    {
      "concepts": [
        "Seasonal Cycles",
        "Riverine Adaptation",
        "Coastal Adaptation",
        "Cerrado Adaptation"
      ],
      "description": "Notice how ways of living changed with floodplains, shorelines, savannas, and yearly rhythms. Ecological knowledge was local, precise, and central to survival and social life.",
      "title": "Adapting to seasons, rivers, coasts, and grasslands"
    },
    {
      "concepts": [
        "Marajoara Society",
        "Tapajonic Ceramics",
        "Santarém Culture",
        "Lagoa Santa"
      ],
      "description": "Anchor the chapter in named archaeological traditions and sites that reveal complexity, artistry, and deep time. These cases help replace vague generalities with specific Indigenous worlds.",
      "title": "Naming major societies and archaeological traditions"
    },
    {
      "concepts": [
        "Xinguano Settlements",
        "Geoglyphs of Acre",
        "Upper Xingu Road Systems"
      ],
      "description": "Look at large-scale planning in the Amazon and nearby regions to see organized settlements, earthworks, and connected communities. These findings overturn older ideas that complex societies could not thrive there.",
      "title": "Finding planned landscapes in the interior"
    },
    {
      "concepts": [
        "Source Bias",
        "Silence in the Record",
        "Ethnographic Analogy"
      ],
      "description": "Handle evidence carefully by asking who created it, what is missing, and how researchers make cautious comparisons. Reconstructing erased histories requires method, not guesswork.",
      "title": "Questioning what the sources can really say"
    }
  ]
}
